def max_diagonal_moves(q, queries):
    results = []
    for n, m, k in queries:
        max_diagonal = -1
        for d in range(min(n, m) + 1):
            remaining_moves = k - d
            if remaining_moves >= 0 and remaining_moves >= abs(n - d) + abs(m - d):
                max_diagonal = max(max_diagonal, d)
        results.append(max_diagonal)
    return results

