def is_permutation(seq, length):
    return set(seq) == set(range(1, length + 1))

def find_permutations(n, a):
    results = []
    for i in range(1, n):
        if is_permutation(a[:i], i) and is_permutation(a[i:], n - i):
            results.append((i, n - i))
    return results

def main():
    import sys
    input = sys.stdin.read
    data = input().split()

    t = int(data[0])
    index = 1
    results = []

    for _ in range(t):
        n = int(data[index])
        a = list(map(int, data[index + 1:index + 1 + n]))
        index += 1 + n

        permutations = find_permutations(n, a)
        results.append((len(permutations), permutations))

    for k, permutations in results:
        print(k)
        for p in permutations:
            print(p[0], p[1])

if __name__ == "__main__":
    main()

def calculate_alice_score(test_cases):
    results = []
    for s in test_cases:
        alice_score = 0
        i = 0
        while i < len(s):
            count = 1
            while i + count < len(s) and s[i] == s[i + count]:
                count += 1
            if s[i] == '1':
                alice_score += count
            i += count
        results.append(alice_score)
    return results

def main():
    import sys
    input = sys.stdin.read
    data = input().split()

    T = int(data[0])
    test_cases = data[1:T+1]

    results = calculate_alice_score(test_cases)

    for result in results:
        print(result)

if __name__ == "__main__":
    main()
